-- XML API request parser for OpenResty SOAP gateway
local cjson = require "cjson"

-- Simple XML parser with entity reference support
local XmlParser = {}
XmlParser.__index = XmlParser

-- XML entity references
local entities = {
    ["&lt;"] = "<",
    ["&gt;"] = ">",
    ["&amp;"] = "&",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

-- Decode entity references
local function decode_entities(str)
    if not str then return str end
    for entity, char in pairs(entities) do
        str = str:gsub(entity, char)
    end
    -- Decode numeric entities
    str = str:gsub("&#(%d+);", function(n)
        return string.char(tonumber(n))
    end)
    str = str:gsub("&#x(%x+);", function(n)
        return string.char(tonumber(n, 16))
    end)
    return str
end

-- Parse XML tag
local function parse_tag(s)
    local tag = {}
    local name = s:match("^<([^%s>/]+)")
    if not name then return nil end
    
    tag.name = name
    tag.attrs = {}
    
    -- Parse attributes
    for attr_name, attr_value in s:gmatch('([%w:_%-]+)%s*=%s*["\']([^"\']*)["\']') do
        tag.attrs[attr_name] = decode_entities(attr_value)
    end
    
    return tag
end

-- Main XML parser
function XmlParser:parse(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "Empty XML string"
    end
    
    local stack = {}
    local root = nil
    local current = nil
    local pos = 1
    
    while pos <= #xml_string do
        -- Find next tag
        local tag_start, tag_end = xml_string:find("<[^>]+>", pos)
        
        if not tag_start then
            -- No more tags, handle remaining text
            if current and pos <= #xml_string then
                local text = xml_string:sub(pos)
                text = text:match("^%s*(.-)%s*$")
                if text ~= "" then
                    current.text = (current.text or "") .. decode_entities(text)
                end
            end
            break
        end
        
        -- Handle text before tag
        if tag_start > pos and current then
            local text = xml_string:sub(pos, tag_start - 1)
            text = text:match("^%s*(.-)%s*$")
            if text ~= "" then
                current.text = (current.text or "") .. decode_entities(text)
            end
        end
        
        local tag_content = xml_string:sub(tag_start, tag_end)
        
        -- Skip XML declaration and comments
        if tag_content:match("^<%?") or tag_content:match("^<!%-%-") then
            pos = tag_end + 1
        -- Handle CDATA
        elseif tag_content:match("^<![CDATA[") then
            local cdata_end = xml_string:find("]]>", tag_end)
            if cdata_end then
                local cdata = xml_string:sub(tag_end + 1, cdata_end - 1)
                if current then
                    current.text = (current.text or "") .. cdata
                end
                pos = cdata_end + 3
            else
                pos = tag_end + 1
            end
        -- Handle closing tag
        elseif tag_content:match("^</") then
            if #stack > 0 then
                current = table.remove(stack)
            end
            pos = tag_end + 1
        -- Handle self-closing tag
        elseif tag_content:match("/>$") then
            local tag = parse_tag(tag_content)
            if tag then
                local node = {
                    name = tag.name,
                    attrs = tag.attrs,
                    children = {}
                }
                
                if current then
                    table.insert(current.children, node)
                else
                    root = node
                end
            end
            pos = tag_end + 1
        -- Handle opening tag
        else
            local tag = parse_tag(tag_content)
            if tag then
                local node = {
                    name = tag.name,
                    attrs = tag.attrs,
                    children = {}
                }
                
                if current then
                    table.insert(current.children, node)
                    table.insert(stack, current)
                else
                    root = node
                end
                current = node
            end
            pos = tag_end + 1
        end
    end
    
    return root
end

-- Helper to find child element by name
function XmlParser:find_child(node, name)
    if not node or not node.children then return nil end
    for _, child in ipairs(node.children) do
        if child.name == name then
            return child
        end
    end
    return nil
end

-- Helper to get all children with given name
function XmlParser:find_children(node, name)
    local results = {}
    if not node or not node.children then return results end
    for _, child in ipairs(node.children) do
        if child.name == name then
            table.insert(results, child)
        end
    end
    return results
end

-- Get text content of node
function XmlParser:get_text(node)
    if not node then return nil end
    return node.text or ""
end

-- Get attribute value
function XmlParser:get_attr(node, attr_name)
    if not node or not node.attrs then return nil end
    return node.attrs[attr_name]
end

-- Convert XML node to Lua table recursively
function XmlParser:to_table(node)
    if not node then return nil end
    
    local result = {}
    result["@name"] = node.name
    
    -- Add attributes
    if node.attrs and next(node.attrs) then
        result["@attrs"] = node.attrs
    end
    
    -- Add text content
    if node.text and node.text ~= "" then
        result["@text"] = node.text
    end
    
    -- Add children
    if node.children and #node.children > 0 then
        result["@children"] = {}
        for _, child in ipairs(node.children) do
            table.insert(result["@children"], self:to_table(child))
        end
    end
    
    return result
end

-- OpenResty request handler
local parser = setmetatable({}, XmlParser)

ngx.req.read_body()
local body = ngx.req.get_body_data()

if not body then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = "No request body"}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local xml_doc, err = parser:parse(body)

if not xml_doc then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = "Invalid XML: " .. (err or "unknown error")}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- Extract SOAP envelope data
local envelope = xml_doc
local soap_body = parser:find_child(envelope, "Body") or parser:find_child(envelope, "soap:Body") or parser:find_child(envelope, "SOAP-ENV:Body")

if not soap_body then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = "Invalid SOAP request: Body not found"}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- Extract operation/method from SOAP body
local operation = nil
if soap_body.children and #soap_body.children > 0 then
    operation = soap_body.children[1]
end

if not operation then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = "No operation found in SOAP body"}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- Store parsed data in ngx.ctx for downstream processing
ngx.ctx.xml_doc = xml_doc
ngx.ctx.soap_body = soap_body
ngx.ctx.operation = operation
ngx.ctx.operation_name = operation.name
ngx.ctx.parser = parser

-- Extract all parameters from operation
local params = {}
if operation.children then
    for _, child in ipairs(operation.children) do
        params[child.name] = parser:get_text(child)
    end
end
ngx.ctx.params = params

-- Log parsed request
ngx.log(ngx.INFO, "SOAP Operation: ", operation.name)
ngx.log(ngx.INFO, "Parameters: ", cjson.encode(params))

ngx.say(cjson.encode({
    success = true,
    operation = operation.name,
    parameters = params
}))